previewCss:
.darma-loader-darma-custom-735 {
  color: var(--loader-color, #8b5cf6);
  --loader-secondary-color: #c4b5fd;
  --loader-bg: #ffffff;
width: 15px;
aspect-ratio: 1;
position: relative;
}
.darma-loader-darma-custom-735::before,
.darma-loader-darma-custom-735::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
background: currentColor;
}
.darma-loader-darma-custom-735::before {
box-shadow: -26px 0;
animation: darma-loader-darma-custom-735-l10-1 1.5s infinite linear;
}
.darma-loader-darma-custom-735::after {
transform: rotate(0deg) translateX(26px);
animation: darma-loader-darma-custom-735-l10-2 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-735-l10-1 {
50%{transform:translateX(26px)}
}
@keyframes darma-loader-darma-custom-735-l10-2 {
100%{transform:rotate(-360deg) translateX(26px)}
}

